    auto query = sqlgen::select_from<A, "t1">(sqlgen::all)
        | sqlgen::inner_join<B, "t2">("t1"_t1.id == "t2"_t2.a_id)
        | sqlgen::where("t2"_t2.score > 10 && "t1"_t1.name.like("%x%"))
