  using namespace sqlgen::literals;

  auto conn_res = sqlite::connect("test_db.sqlite");
  if (!conn_res) return {};
  auto conn = conn_res.value();

  create_table<Customer>(conn);
  create_table<Order>(conn);
  create_table<Payment>(conn);

  const auto query =
